#include <stdio.h>
#include <string.h>

int lcsLength(const char *a, const char *b) {
    int m = strlen(a), n = strlen(b);
    if (n > m) {
        const char *tmp = a; a = b; b = tmp;
        int t = m; m = n; n = t;
    }
    int prev[n + 1];
    int cur[n + 1];
    memset(prev, 0, sizeof(prev));
    for (int i = 1; i <= m; ++i) {
        cur[0] = 0;
        for (int j = 1; j <= n; ++j) {
            if (a[i - 1] == b[j - 1])
                cur[j] = prev[j - 1] + 1;
            else
                cur[j] = (prev[j] > cur[j - 1]) ? prev[j] : cur[j - 1];
        }
        memcpy(prev, cur, sizeof(prev));
    }
    return prev[n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char a[501], b[501];
        scanf("%s %s", a, b);
        int l = lcsLength(a, b);
        int ans = (int)strlen(a) - l + (int)strlen(b) - l;
        printf("%d\n", ans);
    }
    return 0;
}

