#include <bits/stdc++.h>
using namespace std;

int lcsLength(const string &a, const string &b) {
    int m = a.size(), n = b.size();
    if (n > m) return lcsLength(b, a);
    vector<int> prev(n + 1, 0), cur(n + 1, 0);
    for (int i = 1; i <= m; ++i) {
        cur[0] = 0;
        for (int j = 1; j <= n; ++j) {
            if (a[i - 1] == b[j - 1])
                cur[j] = prev[j - 1] + 1;
            else
                cur[j] = max(prev[j], cur[j - 1]);
        }
        swap(prev, cur);
    }
    return prev[n];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T; cin >> T;
    while (T--) {
        string a, b; cin >> a >> b;
        int l = lcsLength(a, b);
        int ans = (int)a.size() - l + (int)b.size() - l;
        cout << ans << '\n';
    }
    return 0;
}

